1153	\paragraph{Stacks 00OE Krull-dimension chain.}
1154	
1155	\begin{lemma}[00OE Step 1 --- localised Krull dimension equals height]
1156	  \label{lem:ringKrullDim_localization_eq_height_atPrime}
1157	  \lean{AlgebraicGeometry.Scheme.ringKrullDim_localization_eq_height_atPrime}
1158	  For a prime ideal \(\mathfrak m\) of a commutative ring \(R\) and any localisation
1159	  \(A\) of \(R\) at \(\mathfrak m\), the Krull dimension of \(A\) equals the height of
1160	  \(\mathfrak m\).
1161	\end{lemma}
1162	
1163	\begin{proof}
1164	  Proved directly in Lean: re-export of Mathlib's
1165	  \texttt{IsLocalization.AtPrime.ringKrullDim\_eq\_height}. A sub-step of
1166	  \cref{lem:ringKrullDim_localization_atMaximal_mvPolynomial}.
1167	\end{proof}
1168	
1169	\begin{lemma}[00OE Step 2 (lower bound) --- height $\ge n$ in $k[\mathrm{Fin}\,n]$]
1170	  \label{lem:mvPolynomial_maximalIdeal_height_ge_card}
1171	  \lean{AlgebraicGeometry.Scheme.MvPolynomial.maximalIdeal_height_ge_card_of_field}
1172	  For a field \(k\), every maximal ideal of the polynomial ring
1173	  \(\mathrm{MvPolynomial}\,(\mathrm{Fin}\,n)\,k\) has height at least \(n\).
1174	\end{lemma}
1175	
1176	\begin{proof}
1177	  Proved directly in Lean: induction on \(n\), transporting the ideal along the
1178	  one-variable-splitting isomorphism and using that adjoining a polynomial variable
1179	  raises height by one, together with the Jacobson contraction of the maximal ideal.
1180	  A sub-step of \cref{lem:mvPolynomial_maximalIdeal_height_eq_card}.
1181	\end{proof}
1182	
1183	\begin{lemma}[00OE Step 2 (upper bound) --- height $\le \#\iota$ in $k[\iota]$]
1184	  \label{lem:mvPolynomial_maximalIdeal_height_le_natCard}
1185	  \lean{AlgebraicGeometry.Scheme.MvPolynomial.maximalIdeal_height_le_natCard_of_field}
1186	  For a field \(k\) and a finite index set \(\iota\), every proper ideal of
1187	  \(\mathrm{MvPolynomial}\,\iota\,k\) has height at most \(\#\iota\).
1188	\end{lemma}
1189	
1190	\begin{proof}
1191	  Proved directly in Lean: height is bounded by the Krull dimension, which for the
1192	  Noetherian polynomial ring over a field equals \(\#\iota\). A sub-step of
1193	  \cref{lem:mvPolynomial_maximalIdeal_height_eq_card}.
1194	\end{proof}
1195	
1196	\begin{lemma}[00OE Step 2 ($\mathrm{Fin}\,n$ form) --- maximal-ideal height equals $n$]
1197	  \label{lem:mvPolynomial_maximalIdeal_height_eq_card}
1198	  \lean{AlgebraicGeometry.Scheme.MvPolynomial.maximalIdeal_height_eq_card}
1199	  \uses{lem:mvPolynomial_maximalIdeal_height_ge_card, lem:mvPolynomial_maximalIdeal_height_le_natCard}
1200	  For a field \(k\), every maximal ideal of
1201	  \(\mathrm{MvPolynomial}\,(\mathrm{Fin}\,n)\,k\) has height exactly \(n\).
1202	\end{lemma}
1203	
1204	\begin{proof}
1205	  Proved directly in Lean: combine the lower bound
1206	  \cref{lem:mvPolynomial_maximalIdeal_height_ge_card} and the upper bound
1207	  \cref{lem:mvPolynomial_maximalIdeal_height_le_natCard} by antisymmetry.
1208	\end{proof}
1209	
1210	\begin{lemma}[00OE Step 2 (general finite form) --- maximal-ideal height equals $\#\iota$]
1211	  \label{lem:mvPolynomial_maximalIdeal_height_eq_natCard}
1212	  \lean{AlgebraicGeometry.Scheme.MvPolynomial.maximalIdeal_height_eq_natCard}
1213	  \uses{lem:mvPolynomial_maximalIdeal_height_eq_card}
1214	  For a field \(k\) and a finite index set \(\iota\), every maximal ideal of
1215	  \(\mathrm{MvPolynomial}\,\iota\,k\) has height exactly \(\#\iota\).
1216	\end{lemma}
1217	
1218	\begin{proof}
1219	  Proved directly in Lean: transport
1220	  \cref{lem:mvPolynomial_maximalIdeal_height_eq_card} along the renaming isomorphism
1221	  induced by a bijection \(\iota \simeq \mathrm{Fin}\,(\#\iota)\). A sub-step of
1222	  \cref{lem:ringKrullDim_localization_atMaximal_mvPolynomial}.
1223	\end{proof}
1224	
1225	\begin{lemma}[00OE Steps 1+2 capstone --- localised polynomial-ring Krull dimension]
1226	  \label{lem:ringKrullDim_localization_atMaximal_mvPolynomial}
1227	  \lean{AlgebraicGeometry.Scheme.ringKrullDim_localization_atMaximal_MvPolynomial}
1228	  \uses{lem:ringKrullDim_localization_eq_height_atPrime, lem:mvPolynomial_maximalIdeal_height_eq_natCard}
1229	  For a field \(k\), a finite index set \(\iota\), and any localisation \(A\) of
1230	  \(\mathrm{MvPolynomial}\,\iota\,k\) at a maximal ideal \(\mathfrak m\), the Krull
1231	  dimension of \(A\) equals \(\#\iota\).
1232	\end{lemma}
1233	
1234	\begin{proof}
1235	  Proved directly in Lean: compose
1236	  \cref{lem:ringKrullDim_localization_eq_height_atPrime} (Krull dimension equals
1237	  height) with \cref{lem:mvPolynomial_maximalIdeal_height_eq_natCard} (height equals
1238	  \(\#\iota\)).
1239	\end{proof}
