1241	\begin{lemma}[00OE Step 3 (additive form) --- dimension drop by a regular sequence]
1242	  \label{lem:ringKrullDim_quotient_add_eq_regular_sequence}
1243	  \lean{AlgebraicGeometry.Scheme.ringKrullDim_quotient_add_eq_of_regular_sequence}
1244	  Let \(R'\) be a Noetherian local ring with \(\mathrm{ringKrullDim}\,R' = a\) and let
1245	  \(rs\) be a regular sequence in \(R'\) of length \(b\). Then
1246	  \(\mathrm{ringKrullDim}\,(R'/(rs)) + b = a\). The additive form is used because the
1247	  value semiring \(\mathrm{WithBot}\,\mathbb N_\infty\) carries no subtraction.
1248	\end{lemma}
1249	
1250	\begin{proof}
1251	  Proved directly in Lean: re-export of Mathlib's
1252	  \texttt{ringKrullDim\_add\_length\_eq\_ringKrullDim\_of\_isRegular} with the
1253	  dimension and length values made explicit. A sub-step of
1254	  \cref{lem:ringKrullDim_quotient_localization_mvPolynomial_regular}.
1255	\end{proof}
1256	
1257	\begin{lemma}[00OE Steps 1+2+3 composite --- localised polynomial-quotient dimension]
1258	  \label{lem:ringKrullDim_quotient_localization_mvPolynomial_regular}
1259	  \lean{AlgebraicGeometry.Scheme.ringKrullDim_quotient_localization_MvPolynomial_of_regular}
1260	  \uses{lem:ringKrullDim_localization_atMaximal_mvPolynomial, lem:ringKrullDim_quotient_add_eq_regular_sequence}
1261	  Let \(A\) be a Noetherian localisation of \(\mathrm{MvPolynomial}\,\iota\,k\) at a
1262	  maximal ideal, and let \(rs\) be a regular sequence in \(A\) of length \(b\). Then
1263	  \(\mathrm{ringKrullDim}\,(A/(rs)) + b = \#\iota\).
1264	\end{lemma}
1265	
1266	\begin{proof}
1267	  Proved directly in Lean: compose the capstone
1268	  \cref{lem:ringKrullDim_localization_atMaximal_mvPolynomial} with the
1269	  regular-sequence dimension drop
1270	  \cref{lem:ringKrullDim_quotient_add_eq_regular_sequence}.
1271	\end{proof}
