1273	\paragraph{Stacks 00SW submersive-presentation cotangent independence.}
1274	
1275	\begin{lemma}[00SW --- relations are cotangent-independent]
1276	  \label{lem:submersive_relation_cotangent_linearIndependent}
1277	  \lean{AlgebraicGeometry.Scheme.submersivePresentation_relation_cotangent_mk_linearIndependent}
1278	  For a submersive presentation \(P\) of an \(R\)-algebra \(S\), the family of
1279	  cotangent classes of the relations \(i \mapsto [\,P.\mathrm{relation}\,i\,]\) in the
1280	  cotangent module of \(P\) is \(S\)-linearly independent.
1281	\end{lemma}
1282	
1283	\begin{proof}
1284	  Proved directly in Lean: re-packaging of the linear independence of the cotangent
1285	  basis of \(P\). A sub-step of
1286	  \cref{lem:submersive_relation_cotangent_linearIndependent_localized}.
1287	\end{proof}
1288	
1289	\begin{lemma}[00SW --- cotangent independence transported to a localisation]
1290	  \label{lem:submersive_relation_cotangent_linearIndependent_localized}
1291	  \lean{AlgebraicGeometry.Scheme.submersivePresentation_relation_cotangent_mk_linearIndependent_localized}
1292	  \uses{lem:submersive_relation_cotangent_linearIndependent}
1293	  With \(P\) a submersive presentation of \(S\) and \(p\) a prime ideal of \(S\), the
1294	  image of the cotangent classes of the relations under the canonical localisation map
1295	  of the cotangent module at \(p\) is \(\mathrm{Localization.AtPrime}\,p\)-linearly
1296	  independent.
1297	\end{lemma}
1298	
1299	\begin{proof}
1300	  Proved directly in Lean: transport
1301	  \cref{lem:submersive_relation_cotangent_linearIndependent} through the localisation
1302	  map, using that linear independence is preserved by a localised-module map.
1303	\end{proof}
