1305	\paragraph{Relative dimension and scheme-to-algebra bridges.}
1306	
1307	\begin{lemma}[Stage 6 sub-gap (i) --- relative dimension of a standard-smooth algebra]
1308	  \label{lem:exists_standardSmoothOfRelativeDimension_of_standardSmooth}
1309	  \lean{AlgebraicGeometry.Scheme.exists_isStandardSmoothOfRelativeDimension_of_isStandardSmooth}
1310	  Every standard-smooth \(R\)-algebra \(S\) is standard smooth of some specific
1311	  relative dimension \(n \in \mathbb N\).
1312	\end{lemma}
1313	
1314	\begin{proof}
1315	  Proved directly in Lean: read the dimension off the underlying submersive
1316	  presentation. A sub-step of \cref{lem:smooth_to_regular_local_ring}.
1317	\end{proof}
1318	
1319	\begin{lemma}[Step B.a --- submersive presentation of a relative-dimension-$n$ algebra]
1320	  \label{lem:exists_submersivePresentation_of_standardSmoothReldim}
1321	  \lean{AlgebraicGeometry.Scheme.exists_submersivePresentation_of_isStandardSmoothOfRelativeDimension}
1322	  \uses{lem:exists_standardSmoothOfRelativeDimension_of_standardSmooth}
1323	  An \(R\)-algebra \(S\) that is standard smooth of relative dimension \(n\) admits an
1324	  explicit submersive presentation \(P\) with \(P.\mathrm{dimension} = n\).
1325	\end{lemma}
1326	
1327	\begin{proof}
1328	  Proved directly in Lean: re-export of the underlying-presentation field of the
1329	  relative-dimension instance.
1330	\end{proof}
1331	
1332	\begin{lemma}[Step B.b --- affine-open stalk is a localisation]
1333	  \label{lem:isLocalization_atPrime_stalk_of_affineOpen}
1334	  \lean{AlgebraicGeometry.Scheme.isLocalization_atPrime_stalk_of_affineOpen}
1335	  For an affine open \(V \ni z\) of a scheme \(X\), the stalk \(\mathcal O_{X,z}\) is
1336	  the localisation of the section ring \(\Gamma(X, V)\) at the prime ideal of \(z\).
1337	\end{lemma}
1338	
1339	\begin{proof}
1340	  Proved directly in Lean: re-export of \texttt{IsAffineOpen.isLocalization\_stalk}.
1341	\end{proof}
1342	
1343	\begin{lemma}[Step B.c helper --- nonempty open on a one-point space is everything]
1344	  \label{lem:open_eq_top_of_subsingleton}
1345	  \lean{AlgebraicGeometry.Scheme.open_eq_top_of_subsingleton}
1346	  On a scheme whose underlying space is a subsingleton (at most one point), every
1347	  nonempty open subset equals the whole space.
1348	\end{lemma}
1349	
1350	\begin{proof}
1351	  Proved directly in Lean: the unique-point argument. A sub-step of
1352	  \cref{lem:gammaSpecField_ringEquiv}.
1353	\end{proof}
1354	
1355	\begin{lemma}[Step B.c --- sections of $\Spec \bar k$ over a nonempty open are $\bar k$]
1356	  \label{lem:gammaSpecField_ringEquiv}
1357	  \lean{AlgebraicGeometry.Scheme.gammaSpecField_ringEquiv}
1358	  \uses{lem:open_eq_top_of_subsingleton}
1359	  For a field \(\bar k\) and any nonempty open \(U\) of \(\Spec(\bar k)\), the section
1360	  ring \(\Gamma(\Spec \bar k, U)\) is ring-isomorphic to \(\bar k\). This gives the
1361	  algebraically-closed base ring of the standard-smooth presentation a clean
1362	  \(\bar k\)-identification.
1363	\end{lemma}
1364	
1365	\begin{proof}
1366	  Proved directly in Lean: \(\Spec(\bar k)\) has a single point, so
1367	  \cref{lem:open_eq_top_of_subsingleton} forces \(U = \top\) and the sections collapse
1368	  to the global sections \(\Gamma(\Spec \bar k, \top) \simeq \bar k\).
1369	\end{proof}
