1371	\paragraph{Matsumura regular-sequence bridge (Stacks 00NQ).}
1372	
1373	\begin{lemma}[Step A1 bridge --- module quotient equals ring quotient]
1374	  \label{lem:quotSMulTop_quotientRing_linearEquiv}
1375	  \lean{AlgebraicGeometry.Scheme.quotSMulTop_quotientRing_linearEquiv}
1376	  For \(r\) in a commutative ring \(A\), there is a canonical \((A/(r))\)-linear
1377	  isomorphism between the module quotient \(A/(r \cdot A)\) and the ring quotient
1378	  \(A/(r)\).
1379	\end{lemma}
1380	
1381	\begin{proof}
1382	  Proved directly in Lean: compose the tensor description of the module quotient with
1383	  the right-unitor and promote scalars along the surjective quotient map. A sub-step of
1384	  \cref{lem:isRegular_cons_of_quotient_ring}.
1385	\end{proof}
1386	
1387	\begin{lemma}[Step A1 bridge --- ring-quotient cons rule for regular sequences]
1388	  \label{lem:isRegular_cons_of_quotient_ring}
1389	  \lean{AlgebraicGeometry.Scheme.isRegular_cons_of_quotient_ring}
1390	  \uses{lem:quotSMulTop_quotientRing_linearEquiv}
1391	  Let \(r \in A\) be such that multiplication by \(r\) is injective on \(A\), and
1392	  suppose the images of a list \(rs\) form a regular sequence over the ring quotient
1393	  \(A/(r)\). Then \(r :: rs\) is a regular sequence over \(A\).
1394	\end{lemma}
1395	
1396	\begin{proof}
1397	  Proved directly in Lean: the module-quotient cons rule transported across the
1398	  identification \cref{lem:quotSMulTop_quotientRing_linearEquiv}. A sub-step of
1399	  \cref{lem:matsumura_isRegular_of_linearIndependent_cotangent}.
1400	\end{proof}
1401	
1402	\begin{lemma}[Step A1 --- cotangent independence descends to the quotient]
1403	  \label{lem:matsumura_descent_cotangent}
1404	  \lean{AlgebraicGeometry.Scheme.matsumura_descent_cotangent}
1405	  Let \((A, \mathfrak m)\) be a local ring and \(f_0,\dots,f_m \in \mathfrak m\) with
1406	  \(\kappa(A)\)-linearly independent cotangent classes. Then the tail
1407	  \(f_1,\dots,f_m\), pushed into the quotient \(A' = A/(f_0)\), has
1408	  \(\kappa(A')\)-linearly independent cotangent classes in
1409	  \(\mathfrak m'/\mathfrak m'^2\).
1410	\end{lemma}
1411	
1412	\begin{proof}
1413	  Proved directly in Lean: the cotangent map \(A \to A'\) is surjective with kernel
1414	  spanned by the class of \(f_0\); a kernel-disjointness argument reduces a
1415	  \(\kappa(A')\)-relation to a \(\kappa(A)\)-relation killed by the full independence
1416	  hypothesis. A sub-step of
1417	  \cref{lem:matsumura_isRegular_of_linearIndependent_cotangent}.
1418	\end{proof}
1419	
1420	\begin{lemma}[Step A1 --- Matsumura: cotangent-independent elements form a regular sequence]
1421	  \label{lem:matsumura_isRegular_of_linearIndependent_cotangent}
1422	  \lean{AlgebraicGeometry.Scheme.matsumura_isRegular_of_linearIndependent_cotangent}
1423	  \uses{lem:matsumura_descent_cotangent, lem:isRegular_cons_of_quotient_ring}
1424	  Let \((A, \mathfrak m)\) be a Noetherian regular local ring and \(f_1,\dots,f_n \in
1425	  \mathfrak m\) whose cotangent classes in \(\mathfrak m/\mathfrak m^2\) are
1426	  \(\kappa(A)\)-linearly independent. Then \(f_1,\dots,f_n\) form a regular sequence in
1427	  \(A\) (Matsumura, \emph{Commutative Ring Theory}, Thm.~14.2; Stacks 00NQ).
1428	\end{lemma}
1429	
1430	\begin{proof}
1431	  Proved directly in Lean: induction on \(n\). The head \(f_1\) is a non-zero-divisor
1432	  (a regular local ring is a domain), the cotangent independence descends to the
1433	  quotient \(A/(f_1)\) by \cref{lem:matsumura_descent_cotangent}, and the
1434	  ring-quotient cons rule \cref{lem:isRegular_cons_of_quotient_ring} reassembles the
1435	  regular sequence. In the standard-smooth application the linear-independence input is
1436	  supplied by the relations of a submersive presentation via
1437	  \cref{lem:submersive_relation_cotangent_linearIndependent_localized}.
1438	\end{proof}
